const items = $input.all();
const changes = items.filter(i => i.json.action && i.json.action !== 'NONE');

if (changes.length === 0) return [];

const stops = changes.filter(i => i.json.action === 'STOP');
const raises = changes.filter(i => i.json.action === 'RAISE_BID');
const lowers = changes.filter(i => i.json.action === 'LOWER_BID');

let msg = `SMART BIDDER ${$now.toFormat('dd.MM.yyyy HH:mm')}\n`;
msg += `Total: ${changes.length} | Up: ${raises.length} | Down: ${lowers.length} | Stop: ${stops.length}\n\n`;

if (stops.length > 0) {
  msg += `STOPPED:\n`;
  stops.forEach(s => {
    const cplStr = s.json.cpl > 0 ? `CPL:$${s.json.cpl}` : 'no leads';
    msg += `${s.json.geo} #${s.json.ad_id}: ${s.json.leads||0}L/${s.json.depositors||0}D ${cplStr} max:$${s.json.max_cpl} $${s.json.spend}spent\n`;
  });
  msg += `\n`;
}

if (raises.length > 0) {
  msg += `BID UP:\n`;
  raises.slice(0, 10).forEach(r => {
    msg += `${r.json.geo} #${r.json.ad_id}: $${r.json.current_bid}->${r.json.new_bid} ${r.json.leads||0}L/${r.json.depositors||0}D CPL:$${r.json.cpl} max:$${r.json.max_cpl}\n`;
  });
  msg += `\n`;
}

if (lowers.length > 0) {
  msg += `BID DOWN:\n`;
  lowers.slice(0, 10).forEach(l => {
    const cplStr = l.json.cpl > 0 ? `CPL:$${l.json.cpl}` : 'no leads';
    msg += `${l.json.geo} #${l.json.ad_id}: $${l.json.current_bid}->${l.json.new_bid} ${l.json.leads||0}L/${l.json.depositors||0}D ${cplStr} max:$${l.json.max_cpl}\n`;
  });
}

return [{ json: { message: msg } }];
